import{_ as a,o as i,c as t,a2 as s}from"./chunks/framework.B08aFN1B.js";const g=JSON.parse('{"title":"Tables","description":"","frontmatter":{},"headers":[],"relativePath":"tables.md","filePath":"tables.md","lastUpdated":null}'),l={name:"tables.md"};function n(r,e,d,o,h,p){return i(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="tables" tabindex="-1">Tables <a class="header-anchor" href="#tables" aria-label="Permalink to &quot;Tables&quot;">​</a></h1><p><code>slate_table</code> renders any table — a <code>DataFrame</code>, any <a href="https://github.com/JuliaData/Tables.jl" target="_blank" rel="noreferrer">Tables.jl</a> source, or a <code>Vector</code> of <code>NamedTuple</code>s — as an interactive, <strong>sortable, filterable, paginated</strong> table. Return it from a cell (a bare <code>DataFrame</code> auto-renders through the same path):</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">slate_table</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(df)</span></span></code></pre></div><p><img class="slate-shot" src="https://github.com/kahliburke/KaimonSlate.jl/releases/download/docs-assets/table.png" alt=""></p><h2 id="Sort,-filter,-page" tabindex="-1">Sort, filter, page <a class="header-anchor" href="#Sort,-filter,-page" aria-label="Permalink to &quot;Sort, filter, page {#Sort,-filter,-page}&quot;">​</a></h2><ul><li><p><strong>Sort</strong> — click a column header; click again to flip ascending/descending. Numeric columns sort numerically, not lexically.</p></li><li><p><strong>Filter</strong> — the box above the table filters rows as you type (a <em>search</em> box for server-paged tables — see <a href="/KaimonSlate.jl/dev/tables#big-data-server-paging">below</a>).</p></li><li><p><strong>Page</strong> — large results paginate, with a page-size control; the footer shows the visible range.</p></li></ul><p>Each column can opt out of sorting or filtering; numeric columns right-align by default.</p><h2 id="Column-formatting" tabindex="-1">Column formatting <a class="header-anchor" href="#Column-formatting" aria-label="Permalink to &quot;Column formatting {#Column-formatting}&quot;">​</a></h2><p>Numbers render cleanly out of the box. For richer display, pass <strong><code>format</code></strong> — a column-name-keyed <code>NamedTuple</code> (or <code>Dict</code>) — with a preset per column:</p><table tabindex="0"><thead><tr><th style="text-align:right;">Preset</th><th style="text-align:right;">Renders</th><th style="text-align:right;">Example</th></tr></thead><tbody><tr><td style="text-align:right;"><code>:currency</code></td><td style="text-align:right;"><code>$1,234.50</code></td><td style="text-align:right;"><code>Revenue = :currency</code></td></tr><tr><td style="text-align:right;"><code>:percent</code></td><td style="text-align:right;"><code>41.8%</code></td><td style="text-align:right;"><code>Margin = :percent</code></td></tr><tr><td style="text-align:right;"><code>:integer</code></td><td style="text-align:right;"><code>1,204</code> (grouped)</td><td style="text-align:right;"><code>Units = :integer</code></td></tr><tr><td style="text-align:right;"><code>:fixed</code></td><td style="text-align:right;"><code>3.14</code></td><td style="text-align:right;"><code>Ratio = :fixed</code></td></tr><tr><td style="text-align:right;"><code>:scientific</code></td><td style="text-align:right;"><code>6.02e23</code></td><td style="text-align:right;"><code>N = :scientific</code></td></tr><tr><td style="text-align:right;"><code>:bytes</code></td><td style="text-align:right;"><code>1.0 MB</code></td><td style="text-align:right;"><code>Size = :bytes</code></td></tr></tbody></table><p>Tune any preset with a spec — <code>(kind = :percent, digits = 1)</code>, <code>(kind = :currency, prefix = &quot;€&quot;)</code>, <code>(kind = :fixed, digits = 3, sep = true)</code>. Alongside <code>format</code>, <strong><code>align</code></strong> (<code>:left</code>/<code>:right</code>/<code>:center</code>) and <strong><code>coltype</code></strong> override the inferred defaults:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">slate_table</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(df;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    format </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (Revenue </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> :currency</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, Margin </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (kind </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> :percent</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, digits </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">), Size </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> :bytes</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">),</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    align  </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (Product </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> :left</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">))</span></span></code></pre></div><p>The same formatting is applied server-side, so it carries into exported HTML and PDF (see <a href="/KaimonSlate.jl/dev/tables#publishing-and-export">Publishing</a>).</p><h2 id="In-cell-visualization" tabindex="-1">In-cell visualization <a class="header-anchor" href="#In-cell-visualization" aria-label="Permalink to &quot;In-cell visualization {#In-cell-visualization}&quot;">​</a></h2><p>Turn a numeric column into an in-cell <strong>bar</strong> or <strong>heat</strong> strip with <strong><code>viz</code></strong> — a compact way to read magnitude down a column at a glance:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">slate_table</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(df; format </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (Revenue </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> :currency</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,), viz </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (Revenue </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> :bar</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, Margin </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> :heat</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">))</span></span></code></pre></div><p><img class="slate-shot" src="https://github.com/kahliburke/KaimonSlate.jl/releases/download/docs-assets/table-formatted.png" alt=""></p><h2 id="Clickable-rows-—-TableSelect" tabindex="-1">Clickable rows — <code>TableSelect</code> <a class="header-anchor" href="#Clickable-rows-—-TableSelect" aria-label="Permalink to &quot;Clickable rows — `TableSelect` {#Clickable-rows-—-TableSelect}&quot;">​</a></h2><p>Bind the row a reader clicks with the <a href="./widgets"><code>TableSelect</code></a> widget — the bound value is that row as a <code>NamedTuple</code>, so downstream cells can read its fields:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">@bind</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> sel </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">TableSelect</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(df)      </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># sel.product, sel.revenue, … ; `nothing` until a row is clicked</span></span></code></pre></div><h2 id="Big-data-—-server-paging" tabindex="-1">Big data — server paging <a class="header-anchor" href="#Big-data-—-server-paging" aria-label="Permalink to &quot;Big data — server paging {#Big-data-—-server-paging}&quot;">​</a></h2><p>For large or lazy data, keep it <strong>server-side</strong> so only the visible page crosses the wire:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">slate_table</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(df; paged </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, page_size </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 100</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># eager table, paged over the wire</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">slate_query</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(provider)                            </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># a lazy, server-paged provider</span></span></code></pre></div><p>Sorting, filtering, and paging then run against the provider <strong>where the cells evaluate</strong> (the gate worker), so a million-row frame stays snappy in the browser.</p><h2 id="In-markdown,-and-when-published" tabindex="-1">In markdown, and when published <a class="header-anchor" href="#In-markdown,-and-when-published" aria-label="Permalink to &quot;In markdown, and when published {#In-markdown,-and-when-published}&quot;">​</a></h2><p>Tables interpolate into markdown cells with double-brace interpolation, so a table can sit inline in your prose (see <a href="/KaimonSlate.jl/dev/notebook-basics#markdown-interpolation">Notebook Basics</a>):</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Latest figures: {{ slate_table(df) }}</span></span></code></pre></div><h3 id="Publishing-and-export" tabindex="-1">Publishing and export <a class="header-anchor" href="#Publishing-and-export" aria-label="Permalink to &quot;Publishing and export {#Publishing-and-export}&quot;">​</a></h3><p>Tables travel well into <a href="./export">exports</a> and <a href="./publishing">published pages</a>:</p><ul><li><p><strong>HTML</strong> — rendered as clean static HTML with the same per-column formatting, alignment, and in-cell bar/heat viz as the live table.</p></li><li><p><strong>PDF (Typst)</strong> — typeset as a themed grid with per-column alignment and the numeric formatting preserved, so a formatted financial table looks right in a publication-quality document.</p></li></ul><p>So a table you style once reads the same in the notebook, in a shared HTML page, and in a printed PDF — no re-authoring.</p>',31)])])}const k=a(l,[["render",n]]);export{g as __pageData,k as default};
